#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use HTML::Entities;

my $cgi = CGI->new;

print $cgi->header('text/html; charset=UTF-8');

my $comment = $cgi->param('comment') || '';

my $sanitized_comment = sanitize_html($comment);

print "<div>$sanitized_comment</div>";

sub sanitize_html {
    my ($text) = @_;
    
    return '' unless defined $text;
    
    $text = encode_entities($text, '<>&"\'');
    
    $text =~ s/&lt;b&gt;/<b>/gi;
    $text =~ s/&lt;\/b&gt;/<\/b>/gi;
    $text =~ s/&lt;i&gt;/<i>/gi;
    $text =~ s/&lt;\/i&gt;/<\/i>/gi;
    $text =~ s/&lt;u&gt;/<u>/gi;
    $text =~ s/&lt;\/u&gt;/<\/u>/gi;
    $text =~ s/&lt;br\s*\/?&gt;/<br>/gi;
    $text =~ s/&lt;p&gt;/<p>/gi;
    $text =~ s/&lt;\/p&gt;/<\/p>/gi;
    
    return $text;
}